function getPageFile(){return`/pages/${"/"==window.location.pathname?"home":window.location.pathname}.php${window.location.search}`}function navigate(a){$(".nav-item[active]").removeAttr("active"),$(`.nav-item[page="${a}"]`).attr("active",""),window.history.replaceState({},a,a),loadPage()}function loadPage(){$.ajax({url:getPageFile(),success:a=>{$("main").html(a),$("main").trigger("page-load")},error:()=>{navigate(`/error/404?path=${window.location.pathname}`)}})}$("window").ready(()=>{navigate(window.location.pathname+window.location.search)}),$("[page]").on("click",a=>{navigate(a.target.getAttribute("page"))});